type WinelioLogoVariant = "color" | "white" | "on-dark";

interface WinelioLogoProps {
  variant?: WinelioLogoVariant;
  height?: number;
  className?: string;
}

// height = hauteur souhaitée du logo en px
// Le W cursif a un viewBox de 216×202 → ratio 1.069
export function WinelioLogo({ variant = "color", height = 44, className }: WinelioLogoProps) {
  const wH = Math.round(height * 1.1);   // hauteur du W légèrement plus grand
  const wW = Math.round(wH * (216 / 202));
  const gap = Math.round(height * 0.04);
  const mb  = Math.round(height * -0.08); // décalage bas pour aligner les baseline

  const wFill =
    variant === "white"
      ? "#ffffff"
      : "url(#wGrad)";

  const textColor =
    variant === "white"   ? "#ffffff"
    : variant === "on-dark" ? "#ffffff"
    : "#3D4A52";

  const gradId = `wGrad-${variant}`;

  return (
    <span
      className={className}
      style={{
        display: "inline-flex",
        alignItems: "flex-end",
        lineHeight: 1,
        gap: 0,
      }}
    >
      {/* W cursif en SVG inline */}
      <svg
        viewBox="0 0 216 202"
        width={wW}
        height={wH}
        style={{ display: "block", marginRight: gap, marginBottom: mb, flexShrink: 0 }}
        aria-hidden="true"
      >
        <defs>
          <linearGradient id={gradId} x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="#FF6B35" />
            <stop offset="100%" stopColor="#F7931E" />
          </linearGradient>
        </defs>
        <path d={W_PATH} fill={variant === "white" ? "#ffffff" : `url(#${gradId})`} />
      </svg>

      {/* inelio en Poppins Bold via CSS variable */}
      <span
        style={{
          fontFamily: "var(--font-poppins), 'Helvetica Neue', Arial, sans-serif",
          fontWeight: 700,
          fontSize: height,
          color: textColor,
          letterSpacing: "-0.04em",
          lineHeight: 1,
        }}
      >
        inelio
      </span>
    </span>
  );
}
